import React, { useState } from "react";
import axios from "axios";

export default function Register() {
  const [email, setEmail] = useState("");
  const [username, setUsername] = useState("");
  const [password, setPassword] = useState("");
  const [error, setError] = useState("");

  async function register() {
    try {
      await axios.post("http://localhost:5000/api/auth/register", {
        email,
        username,
        password,
      });
      // Optionally redirect to login or auto-login
    } catch {
      setError("Registration failed. Please try again.");
    }
  }

  function handleSubmit(e) {
    e.preventDefault();
    register();
  }

  const inputStyle = {
    width: "100%",
    padding: "10px 14px",
    borderRadius: 8,
    border: "1px solid #D1D8ED",
    fontSize: 16,
    margin: "14px 0 0 0",
    boxSizing: "border-box",
  };

  return (
    <div
      style={{
        background: "#EAEFF9",
        minHeight: "100vh",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
      }}
    >
      <form
        onSubmit={handleSubmit}
        style={{
          background: "#fff",
          padding: "2.5rem",
          borderRadius: 18,
          boxShadow: "0 4px 16px #BDBDBD26",
          width: 350,
        }}
      >
        <h2 style={{ color: "#5D5FEF", textAlign: "center", marginBottom: 24 }}>
          Register
        </h2>
        <input
          type="email"
          placeholder="Email"
          value={email}
          onChange={(e) => setEmail(e.target.value)}
          required
          style={inputStyle}
        />
        <input
          type="text"
          placeholder="Username"
          value={username}
          onChange={(e) => setUsername(e.target.value)}
          required
          style={inputStyle}
        />
        <input
          type="password"
          placeholder="Password"
          value={password}
          onChange={(e) => setPassword(e.target.value)}
          required
          style={inputStyle}
        />
        <button
          type="submit"
          style={{
            background: "#5D5FEF",
            color: "#fff",
            borderRadius: 12,
            border: 0,
            padding: "10px",
            fontWeight: 600,
            fontSize: 16,
            width: "100%",
            marginTop: 14,
            cursor: "pointer",
          }}
        >
          Register
        </button>
        {error && <p style={{ color: "#C44737", marginTop: 14 }}>{error}</p>}
      </form>
    </div>
  );
}
